import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Temperature',
        data: [-2, 0, 6, 12, 18, 24, 28, 27, 21, 14, 7, 1],
      },
    ],
    options: {
      chart: {
        height: 350,
        type: 'line',
      },
      stroke: {
        width: 14,
        curve: 'smooth',
      },
      xaxis: {
        categories: [
          'Jan',
          'Feb',
          'Mar',
          'Apr',
          'May',
          'Jun',
          'Jul',
          'Aug',
          'Sep',
          'Oct',
          'Nov',
          'Dec',
        ],
      },
      title: {
        text: 'Average Daily Temperature',
        align: 'left',
        style: {
          fontSize: '16px',
        },
      },
      subtitle: {
        text: 'The line stroke is painted with an image fill',
        align: 'left',
      },
      fill: {
        type: 'image',
        image: {
          src: ['../../assets/images/2979121308_59539a3898_z.jpg'],
          width: 640,
          height: 424,
        },
      },
      markers: {
        size: 0,
        opacity: 0,
        colors: ['#fff'],
        strokeColor: '#2e93fa',
        strokeWidth: 2,
        hover: {
          size: 8,
        },
      },
      yaxis: {
        title: {
          text: 'Temperature (°C)',
        },
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="line"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
